from django.http import HttpResponse
from django.contrib.auth import login, get_user_model
from django.views.decorators.csrf import csrf_exempt
from django.utils import timezone
from xml.etree import ElementTree as ET
from django.contrib.sessions.models import Session

User = get_user_model()

@csrf_exempt
def saml_response(request):
    if request.method == 'POST':
        # Parse SAML XML from request body
        try:
            root = ET.fromstring(request.body)
        except ET.ParseError:
            return HttpResponse("Invalid XML", status=400)
        
        # Basic SAML XML structure validation
        if root.tag != '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
            return HttpResponse("Invalid SAML Response", status=400)

        # Extract NameID
        name_id = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        if name_id is None or name_id.text is None:
            return HttpResponse("NameID missing in SAML Response", status=400)

        # Extract Attributes
        attributes = {}
        attr_statement = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement')
        if attr_statement:
            for attribute in attr_statement.findall('{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
                attr_name = attribute.get('Name')
                if attr_name:
                    attr_values = [value.text for value in attribute.findall('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')]
                    attributes[attr_name] = attr_values

        # Create Django user sessions
        user, created = User.objects.get_or_create(username=name_id.text)
        user.email = attributes.get('email', [None])[0]
        user.first_name = attributes.get('first_name', [None])[0]
        user.last_name = attributes.get('last_name', [None])[0]
        user.save()

        login(request, user)

        # Optionally log session creation
        Session(user=user, session_key=request.session.session_key, expire_date=timezone.now()).save()

        return HttpResponse("SAML Response processed", status=200)

    return HttpResponse("Invalid request method", status=405)

